    if (startIndex === -1 || endIndex === -1) {
      return null;
    }

    return text.substring(startIndex + startTag.length, endIndex).trim();
  }

  const content = extractContent(input, 'query');

  if (!content) {
    return {
      error: 'Cannot find <query>...</query> content'
    };
  }

  const parts = content.split(/[；;]/).map(part => part.trim());

  return {
    title1: parts[0] || '',
    title2: parts[1] || '',
    title3: parts[2] || '',
    title4: parts[3] || '',
    title5: parts[4] || ''
  };
}

function main({input}) {
  function extractContent(text, tagName) {
    const startTag = `<${tagName}>`
    const endTag = `</${tagName}>`

    const startIndex = text.indexOf(startTag)
    const endIndex = text.indexOf(endTag)

    if(startIndex === -1 || endIndex === -1) {
      return `Error: Cannot find ${tagName} tags`
    }

    return text.substring(startIndex + startTag.length, endIndex)
  }

  return {
    query: extractContent(input, 'query')
  }
}

function main({ responseBody }) {
    try {
        const response = typeof responseBody === 'string' ? JSON.parse(responseBody) : responseBody;
        const dataObj = JSON.parse(response.data);
        const articles = [];

        for (let i = 0; i < 20; i++) {
            articles.push({ title: "", content: "" });
        }

        function cleanText(text) {
            const emojiCleaned = text.replace(/\[[^\]]+\s[A-Z]\]/g, '');
            const hashtagCleaned = emojiCleaned.replace(/(\s*#[^#]*\[话题\]#\s*)+$/g, '');
            return hashtagCleaned.replace(/\s+/g, ' ').trim();
        }

        if (dataObj.output && Array.isArray(dataObj.output)) {
            for (let i = 0; i < Math.min(20, dataObj.output.length); i++) {
                const item = dataObj.output[i];
                const parts = item.split(/\n\s*正文：/);

                let title = "";
                let content = "";

                if (parts.length > 1) {
                    title = parts[0].replace('标题：', '').trim();
                    content = parts[1].trim();
                } else if (item.startsWith('标题：')) {
                    title = item.replace('标题：', '').trim();
                } else if (item.includes('正文：')) {
                    content = item.replace('正文：', '').trim();
                } else {
                    content = item.trim();
                }

                content = cleanText(content);

                articles[i] = { title };
            }
        }

        // 将标题数组转为逗号分隔的字符串
        const titles = articles
            .map(article => article.title)
            .filter(title => title) // 过滤空标题
            .join(', ');

        return {
            titles,
            debug_url: response.debug_url
        };
    } catch (error) {
        return {
            error: `解析失败: ${error.message}`,
            originalResponse: responseBody
        };
    }
}

